import React from "react";
import './project1.css'

function Project1() {
    return (
      <div id="project1-body">
          <h4>Stranger's Things</h4>
          <p id="project1-description">
            A REACT CRUD application that allows users to register an account and buy and sell items on the marketplace. Tech stack: REACT, JSON, HTML, REST API, HTML/CSS, Material UI.
          </p>
          <div>
            <ul id="project1-links-ul">
                <li id="project1-link1"></li>
                <li id="project1-link2">Link2</li>
            </ul>
          </div>
      </div>
    )
  }

export default Project1;
